import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";import{n as o,t as s}from"./chunks/gradle-prompt.DgUqZl-T.js";const c=JSON.parse(`{"title":"Creating a Project","description":"A step-by-step guide on how to create a new mod project using the Fabric template mod generator.","frontmatter":{"title":"Creating a Project","description":"A step-by-step guide on how to create a new mod project using the Fabric template mod generator.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"1.20.4/develop/getting-started/creating-a-project.md","filePath":"versions/1.20.4/develop/getting-started/creating-a-project.md","lastUpdated":1774372461000}`);var l={name:`1.20.4/develop/getting-started/creating-a-project.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Creating a Project <a class="header-anchor" href="#h1" aria-label="Permalink to “Creating a Project”">​</a></h1><p>Fabric provides an easy way to create a new mod project using the Fabric Template Mod Generator - if you want, you can manually create a new project using the example mod repository, you should refer to the <a href="#manual-project-creation">Manual Project Creation</a> section.</p><h2 id="generating-a-project" tabindex="-1">Generating a Project <a class="header-anchor" href="#generating-a-project" aria-label="Permalink to “Generating a Project”">​</a></h2><p>You can use the <a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">Fabric Template Mod Generator</a> to generate a new project for your mod - you should fill in the required fields, such as the package name and mod name, and the Minecraft version that you want to develop for.</p><p><img src="/assets/develop/getting-started/template-generator.png" alt="Preview of the generator" loading="lazy"></p><p>If you either want to use Kotlin, or Fabric&#39;s Yarn mappings instead of the default Mojang Mappings, or want to add data generators, you can select the appropriate options in the <code>Advanced Options</code> section.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Code examples given on this site use Mojang&#39;s official mappings. If your mod is not using the same mappings that these docs are written in, you will need to convert the examples using sites like <a href="https://mappings.dev/" target="_blank" rel="noreferrer">mappings.dev</a> or <a href="https://linkie.shedaniel.dev/mappings?namespace=yarn&amp;translateMode=ns&amp;translateAs=mojang_raw&amp;search=" target="_blank" rel="noreferrer">Linkie</a>.</p></div><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="Advanced options section" loading="lazy"></p><p>Once you&#39;ve filled in the required fields, click the <code>Generate</code> button, and the generator will create a new project for you to use in the form of a zip file.</p><p>You should extract this zip file to a location of your choice, and then open the extracted folder in IntelliJ IDEA:</p><p><img src="/assets/develop/getting-started/open-project.png" alt="Open Project Prompt" loading="lazy"></p><h2 id="importing-the-project" tabindex="-1">Importing the Project <a class="header-anchor" href="#importing-the-project" aria-label="Permalink to “Importing the Project”">​</a></h2><p>Once you&#39;ve opened the project in IntelliJ IDEA, the IDE should automatically load the project&#39;s Gradle configuration and perform the necessary setup tasks.</p><p>If you receive a notification talking about a Gradle build script, you should click the <code>Import Gradle Project</code> button:</p><p><img src="/assets/develop/getting-started/gradle-prompt.png" alt="Gradle Prompt" loading="lazy"></p><p>Once the project has been imported, you should see the project&#39;s files in the project explorer, and you should be able to start developing your mod.</p><h2 id="manual-project-creation" tabindex="-1">Manual Project Creation <a class="header-anchor" href="#manual-project-creation" aria-label="Permalink to “Manual Project Creation”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>You will need <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a> installed in order to clone the example mod repository.</p></div><p>If you cannot use the Fabric Template Mod Generator, you can create a new project manually by following these steps.</p><p>Firstly, clone the example mod repository using Git:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-mod-project</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This will clone the repository into a new folder called <code>my-mod-project</code>.</p><p>You should then delete the <code>.git</code> folder from the cloned repository, and then open the project in IntelliJ IDEA. If the <code>.git</code> folder does not appear, you should enable the display of hidden files in your file manager.</p><p>Once you&#39;ve opened the project in IntelliJ IDEA, it should automatically load the project&#39;s Gradle configuration and perform the necessary setup tasks.</p><p>Again, as previously mentioned, if you receive a notification talking about a Gradle build script, you should click the <code>Import Gradle Project</code> button.</p><h3 id="modifying-the-template" tabindex="-1">Modifying the Template <a class="header-anchor" href="#modifying-the-template" aria-label="Permalink to “Modifying the Template”">​</a></h3><p>Once the project has been imported, you should modify the project&#39;s details to match your mod&#39;s details:</p><ul><li>Modify the project&#39;s <code>gradle.properties</code> file to change the <code>maven_group</code> and <code>archive_base_name</code> properties to match your mod&#39;s details.</li><li>Modify the <code>fabric.mod.json</code> file to change the <code>id</code>, <code>name</code>, and <code>description</code> properties to match your mod&#39;s details.</li><li>Make sure to update the versions of Minecraft, the mappings, the Loader and the Loom - all of which can be queried through <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">https://fabricmc.net/develop/</a> - to match the versions you wish to target.</li></ul><p>You can obviously change the package name and the mod&#39;s main class to match your mod&#39;s details.</p>`,29)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};